<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Desktop Environment</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Ubuntu', 'Segoe UI', sans-serif;
            background: #2d2d2d;
            overflow: hidden;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #1e3c72 0%, #2a5298 100%);
            display: flex;
            flex-direction: column;
        }

        .desktop-content {
            flex: 1;
            position: relative;
            overflow: hidden;
        }

        #taskbar {
            background: #333333;
            border-top: 1px solid #555;
            padding: 8px;
            display: flex;
            gap: 8px;
            height: 56px;
        }

        #taskbar button {
            background: #404040;
            color: #fff;
            border: 1px solid #555;
            padding: 8px 16px;
            cursor: pointer;
            border-radius: 4px;
            font-size: 14px;
            transition: background 0.2s;
        }

        #taskbar button:hover {
            background: #505050;
        }

        #taskbar button:active {
            background: #303030;
        }

        .window {
            position: absolute;
            background: #f5f5f5;
            border-radius: 8px;
            box-shadow: 0 4px 16px rgba(0, 0, 0, 0.3);
            display: flex;
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
            z-index: 100;
        }

        .window.hidden {
            display: none;
        }

        .window-header {
            background: linear-gradient(to right, #f8f8f8, #e8e8e8);
            padding: 12px;
            border-bottom: 1px solid #ddd;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            border-radius: 8px 8px 0 0;
            user-select: none;
        }

        .window-header h2 {
            font-size: 14px;
            font-weight: 500;
            flex: 1;
        }

        .win-close {
            background: #f44747;
            color: white;
            border: none;
            width: 32px;
            height: 32px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 18px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: background 0.2s;
            flex-shrink: 0;
        }

        .win-close:hover {
            background: #d32f2f;
        }

        .window-body {
            flex: 1;
            padding: 16px;
            overflow: auto;
            background: #ffffff;
        }

        #files-window {
            width: 500px;
            height: 400px;
            top: 100px;
            left: 100px;
        }

        #notepad-window {
            width: 600px;
            height: 400px;
            top: 150px;
            left: 150px;
        }

        #files-path {
            background: #f0f0f0;
            padding: 8px 12px;
            border-radius: 4px;
            margin-bottom: 12px;
            font-family: monospace;
            font-size: 13px;
            word-break: break-all;
        }

        .files-toolbar {
            display: flex;
            gap: 8px;
            margin-bottom: 12px;
        }

        .files-toolbar button {
            background: #404040;
            color: #fff;
            border: 1px solid #555;
            padding: 6px 12px;
            cursor: pointer;
            border-radius: 4px;
            font-size: 12px;
        }

        .files-toolbar button:hover {
            background: #505050;
        }

        #files-list {
            border: 1px solid #ddd;
            border-radius: 4px;
            overflow-y: auto;
            background: #fff;
            max-height: 250px;
        }

        .fs-item {
            padding: 10px 12px;
            border-bottom: 1px solid #eee;
            cursor: pointer;
            user-select: none;
            transition: background 0.15s;
        }

        .fs-item:last-child {
            border-bottom: none;
        }

        .fs-item:hover {
            background: #f0f0f0;
        }

        .fs-item.folder::before {
            content: "📁 ";
        }

        .fs-item.file::before {
            content: "📄 ";
        }

        #tabs {
            display: flex;
            gap: 4px;
            margin-bottom: 12px;
            border-bottom: 1px solid #ddd;
            padding-bottom: 4px;
            flex-wrap: wrap;
        }

        .tab {
            background: #e0e0e0;
            border: 1px solid #ccc;
            padding: 8px 12px;
            cursor: pointer;
            border-radius: 4px 4px 0 0;
            font-size: 13px;
            transition: background 0.2s;
        }

        .tab:hover {
            background: #d0d0d0;
        }

        .tab.active {
            background: #fff;
            border-bottom-color: #fff;
        }

        #new-tab {
            background: #404040;
            color: #fff;
            border: 1px solid #555;
            padding: 6px 12px;
            cursor: pointer;
            border-radius: 4px;
            font-size: 12px;
            margin-left: auto;
            flex-shrink: 0;
        }

        #new-tab:hover {
            background: #505050;
        }

        #editor {
            width: 100%;
            height: 100%;
            padding: 12px;
            border: 1px solid #ddd;
            border-radius: 4px;
            font-family: 'Monaco', 'Courier New', monospace;
            font-size: 13px;
            resize: none;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <div class="desktop-content">
            <div id="files-window" class="window hidden">
                <div class="window-header">
                    <h2>Files</h2>
                    <button class="win-close">✕</button>
                </div>
                <div class="window-body">
                    <div id="files-path">/</div>
                    <div class="files-toolbar">
                        <button id="files-up">← Up</button>
                    </div>
                    <div id="files-list"></div>
                </div>
            </div>

            <div id="notepad-window" class="window hidden">
                <div class="window-header">
                    <h2>Notepad</h2>
                    <button class="win-close">✕</button>
                </div>
                <div class="window-body">
                    <div style="display: flex; gap: 8px; margin-bottom: 12px; align-items: center;">
                        <div id="tabs" style="flex: 1;"></div>
                        <button id="new-tab">+ New</button>
                    </div>
                    <textarea id="editor" placeholder="Start typing..."></textarea>
                </div>
            </div>
        </div>

        <div id="taskbar">
            <button id="open-files">Files</button>
            <button id="open-notepad">Notepad</button>
        </div>
    </div>

    <script>
        const fileSystem = {
            '/': ['bin', 'etc', 'home', 'usr', 'var'],
            '/bin': [],
            '/etc': [],
            '/usr': [],
            '/var': [],
            '/home': ['user'],
            '/home/user': ['Documents', 'Downloads', 'Pictures'],
            '/home/user/Documents': ['resume.txt', 'notes.txt'],
            '/home/user/Downloads': ['image.jpg', 'archive.zip'],
            '/home/user/Pictures': ['photo1.jpg', 'photo2.jpg']
        };

        const folders = new Set(['/', 'bin', 'etc', 'home', 'usr', 'var', 'user', 'Documents', 'Downloads', 'Pictures']);
        let currentPath = '/';

        function renderFileList() {
            const list = document.getElementById('files-list');
            list.innerHTML = '';
            const items = fileSystem[currentPath] || [];
            items.forEach(item => {
                const div = document.createElement('div');
                div.className = `fs-item ${folders.has(item) ? 'folder' : 'file'}`;
                div.textContent = item;
                if (folders.has(item)) {
                    div.addEventListener('dblclick', () => {
                        currentPath = currentPath === '/' ? `/${item}` : `${currentPath}/${item}`;
                        document.getElementById('files-path').textContent = currentPath;
                        renderFileList();
                    });
                }
                list.appendChild(div);
            });
        }

        document.getElementById('files-up').addEventListener('click', () => {
            if (currentPath !== '/') {
                currentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';
                document.getElementById('files-path').textContent = currentPath;
                renderFileList();
            }
        });

        renderFileList();

        let tabs = JSON.parse(localStorage.getItem('notepad-tabs')) || [{ id: 1, title: 'Tab 1', content: '' }];
        let nextId = Math.max(...tabs.map(t => t.id), 0) + 1;
        let activeTabId = tabs[0]?.id || 1;

        function renderTabs() {
            const tabsContainer = document.getElementById('tabs');
            tabsContainer.innerHTML = '';
            tabs.forEach(tab => {
                const tabEl = document.createElement('div');
                tabEl.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabEl.textContent = tab.title;
                tabEl.addEventListener('click', () => {
                    const currentTab = tabs.find(t => t.id === activeTabId);
                    if (currentTab) currentTab.content = document.getElementById('editor').value;
                    activeTabId = tab.id;
                    renderTabs();
                    renderEditor();
                    saveTabs();
                });
                tabsContainer.appendChild(tabEl);
            });
        }

        function renderEditor() {
            const activeTab = tabs.find(t => t.id === activeTabId);
            document.getElementById('editor').value = activeTab?.content || '';
        }

        function saveTabs() {
            localStorage.setItem('notepad-tabs', JSON.stringify(tabs));
        }

        document.getElementById('new-tab').addEventListener('click', () => {
            const currentTab = tabs.find(t => t.id === activeTabId);
            if (currentTab) currentTab.content = document.getElementById('editor').value;
            const newTab = { id: nextId++, title: `Tab ${nextId}`, content: '' };
            tabs.push(newTab);
            activeTabId = newTab.id;
            renderTabs();
            renderEditor();
            saveTabs();
        });

        document.getElementById('editor').addEventListener('input', () => {
            const activeTab = tabs.find(t => t.id === activeTabId);
            if (activeTab) {
                activeTab.content = document.getElementById('editor').value;
                saveTabs();
            }
        });

        renderTabs();
        renderEditor();

        function setupWindowClose(windowId) {
            const window = document.getElementById(windowId);
            window.querySelector('.win-close').addEventListener('click', () => {
                window.classList.add('hidden');
            });
        }

        document.getElementById('open-files').addEventListener('click', () => {
            document.getElementById('files-window').classList.remove('hidden');
        });

        document.getElementById('open-notepad').addEventListener('click', () => {
            document.getElementById('notepad-window').classList.remove('hidden');
        });

        setupWindowClose('files-window');
        setupWindowClose('notepad-window');

        function makeDraggable(windowId) {
            const windowEl = document.getElementById(windowId);
            const header = windowEl.querySelector('.window-header');
            let isDragging = false;
            let initialX, initialY;

            header.addEventListener('mousedown', (e) => {
                if (e.target.classList.contains('win-close')) return;
                isDragging = true;
                initialX = e.clientX - windowEl.offsetLeft;
                initialY = e.clientY - windowEl.offsetTop;
            });

            document.addEventListener('mousemove', (e) => {
                if (isDragging && !windowEl.classList.contains('hidden')) {
                    windowEl.style.left = (e.clientX - initialX) + 'px';
                    windowEl.style.top = (e.clientY - initialY) + 'px';
                }
            });

            document.addEventListener('mouseup', () => {
                isDragging = false;
            });
        }

        makeDraggable('files-window');
        makeDraggable('notepad-window');
    </script>
</body>
</html>
